class Solution {
    public int findTheLongestSubstring(String s) {
        int maxLen = 0;
        int[] vowel = new int[1 << 5]; // 32 bits to represent 5 vowels
        int state = 0;
        vowel[0] = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if ("aeiou".indexOf(c) != -1) {
                state ^= 1 << ("aeiou".indexOf(c));
            }
            if (vowel[state] != 0) {
                maxLen = Math.max(maxLen, i - vowel[state] + 1);
            } else {
                vowel[state] = i + 1;
            }
        }
        return maxLen;
    }
}
